269: func promptMFAChallenge(ctx context.Context, proxyAddr string, c *proto.MFAAuthenticateChallenge) (*proto.MFAAuthenticateResponse, error) {
270: 	switch {
271: 	// No challenge.
272: 	case c.TOTP == nil && len(c.U2F) == 0:
273: 		return &proto.MFAAuthenticateResponse{}, nil
274: 	// TOTP only.
275: 	case c.TOTP != nil && len(c.U2F) == 0:
276: 		totpCode, err := prompt.Input(os.Stdout, os.Stdin, "Enter an OTP code from a *registered* device")
277: 		if err != nil {
278: 			return nil, trace.Wrap(err)
279: 		}
280: 		return &proto.MFAAuthenticateResponse{Response: &proto.MFAAuthenticateResponse_TOTP{
281: 			TOTP: &proto.TOTPResponse{Code: totpCode},
282: 		}}, nil
283: 	// U2F only.
284: 	case c.TOTP == nil && len(c.U2F) > 0:
285: 		fmt.Println("Tap any *registered* security key")
286: 
287: 		return promptU2FChallenges(ctx, proxyAddr, c.U2F)
288: 	// Both TOTP and U2F.
289: 	case c.TOTP != nil && len(c.U2F) > 0:
290: 		ctx, cancel := context.WithCancel(ctx)
291: 		defer cancel()
292: 
293: 		type response struct {
294: 			kind string
295: 			resp *proto.MFAAuthenticateResponse
296: 			err  error
297: 		}
298: 		resCh := make(chan response)
299: 
300: 		go func() {
301: 			resp, err := promptU2FChallenges(ctx, proxyAddr, c.U2F)
302: 			select {
303: 			case resCh <- response{kind: "U2F", resp: resp, err: err}:
304: 			case <-ctx.Done():
305: 			}
306: 		}()
307: 
308: 		go func() {
309: 			totpCode, err := prompt.Input(os.Stdout, os.Stdin, "Tap any *registered* security key or enter an OTP code from a *registered* device")
310: 			res := response{kind: "TOTP", err: err}
311: 			if err == nil {
312: 				res.resp = &proto.MFAAuthenticateResponse{Response: &proto.MFAAuthenticateResponse_TOTP{
313: 					TOTP: &proto.TOTPResponse{Code: totpCode},
314: 				}}
315: 			}
316: 
317: 			select {
318: 			case resCh <- res:
319: 			case <-ctx.Done():
320: 			}
321: 		}()
322: 
323: 		for i := 0; i < 2; i++ {
324: 			select {
325: 			case res := <-resCh:
326: 				if res.err != nil {
327: 					log.WithError(res.err).Debugf("%s authentication failed", res.kind)
328: 					continue
329: 				}
330: 
331: 				// Print a newline after the TOTP prompt, so that any future
332: 				// output doesn't print on the prompt line.
333: 				fmt.Println()
334: 
335: 				return res.resp, nil
336: 			case <-ctx.Done():
337: 				return nil, trace.Wrap(ctx.Err())
338: 			}
339: 		}
340: 		return nil, trace.Errorf("failed to authenticate using all U2F and TOTP devices, rerun the command with '-d' to see error details for each device")
341: 	default:
342: 		return nil, trace.BadParameter("bug: non-exhaustive switch in promptMFAChallenge")
343: 	}
344: }
