{"content":"1214: func (g *GRPCServer) AddMFADevice(stream proto.AuthService_AddMFADeviceServer) error {
1215: 	actx, err := g.authenticate(stream.Context())
1216: 	if err != nil {
1217: 		return trail.ToGRPC(err)
1218: 	}
1219: 
1220: 	// The RPC is streaming both ways and the message sequence is:
1221: 	// (-> means client-to-server, <- means server-to-client)
1222: 	//
1223: 	// 1. -> Init
1224: 	// 2. <- ExistingMFAChallenge
1225: 	// 3. -> ExistingMFAResponse
1226: 	// 4. <- NewMFARegisterChallenge
1227: 	// 5. -> NewMFARegisterResponse
1228: 	// 6. <- Ack
1229: 
1230: 	// 1. receive client Init
1231: 	initReq, err := addMFADeviceInit(actx, stream)
1232: 	if err != nil {
1233: 		return trail.ToGRPC(err)
1234: 	}
1235: 
1236: 	// 2. send ExistingMFAChallenge
1237: 	// 3. receive and validate ExistingMFAResponse
1238: 	if err := addMFADeviceAuthChallenge(actx, stream); err != nil {
1239: 		return trail.ToGRPC(err)
1240: 	}
1241: 
1242: 	// 4. send MFARegisterChallenge
1243: 	// 5. receive and validate MFARegisterResponse
1244: 	dev, err := addMFADeviceRegisterChallenge(actx, stream, initReq)
1245: 	if err != nil {
1246: 		return trail.ToGRPC(err)
1247: 	}
1248: 
1249: 	// 6. send Ack
1250: 	if err := stream.Send(&proto.AddMFADeviceResponse{
1251: 		Response: &proto.AddMFADeviceResponse_Ack{Ack: &proto.AddMFADeviceResponseAck{Device: dev}},
1252: 	}); err != nil {
1253: 		return trail.ToGRPC(err)
1254: 	}
1255: 	return nil
1256: }
