1258: func addMFADeviceInit(gctx *grpcContext, stream proto.AuthService_AddMFADeviceServer) (*proto.AddMFADeviceRequestInit, error) {
1259: 	req, err := stream.Recv()
1260: 	if err != nil {
1261: 		return nil, trace.Wrap(err)
1262: 	}
1263: 	initReq := req.GetInit()
1264: 	if initReq == nil {
1265: 		return nil, trace.BadParameter("expected AddMFADeviceRequestInit, got %T", req)
1266: 	}
1267: 	devs, err := gctx.authServer.GetMFADevices(stream.Context(), gctx.User.GetName())
1268: 	if err != nil {
1269: 		return nil, trace.Wrap(err)
1270: 	}
1271: 	for _, d := range devs {
1272: 		if d.Metadata.Name == initReq.DeviceName {
